#include <stddef.h>

void filter_positives(const int* src, int* dest, size_t len, size_t* out_len) {
    size_t count = 0;
    for (size_t i = 0; i < len; i++) {
        if (src[i] > 0) { dest[count++] = src[i]; }
    }
    *out_len = count;
}

